import{_ as a,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"铁桶","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/1.D级/铁桶.md","filePath":"4.资源分区/7.物品与装备/4.奇物/1.D级/铁桶.md"}'),d={name:"4.资源分区/7.物品与装备/4.奇物/1.D级/铁桶.md"};function l(b,r,i,_,p,c){return t(),n("div",null,[...r[0]||(r[0]=[e("h1",{id:"铁桶",tabindex:"-1"},[s("铁桶 "),e("a",{class:"header-anchor",href:"#铁桶","aria-label":'Permalink to "铁桶"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌034")])])],-1),o('<h1 id="铁桶-1" tabindex="-1">铁桶 <a class="header-anchor" href="#铁桶-1" aria-label="Permalink to &quot;铁桶&quot;">​</a></h1><p>铁桶<br> d+500<br> 特异本质<br> 类型：奇物/头盔<br> 原典：我的世界 植物大战僵尸 泰拉瑞亚<br> 这，是一个铁桶，你可以用它来装水，装岩浆，也可以用它来接牛奶，更可以把它直接戴在头上。<br> 无限水<br> 就算在一个水源不足一桶的地方，若你对接触距离内的水使用空桶接取，那么你将可以成功其装在桶内，同时，你会发现你并未遵守质量守恒定律的取得一整桶水。<br> 落地水<br> 在你即将坠落时，若你的桶中有水并且此刻正被你手持，那么你可以通过一个自由行动在脚下放置一桶水来使得你免疫坠落伤害。<br> 牛奶桶<br> 若你正好遇上了牛，那么你就可以获得牛奶，将空桶对准接触距离内的牛类生物使用一个自由动作，空桶内将被牛奶填满，无论该生物是雌性还是雄性，因为在我的世界牛没有性别（）<br> 喝下一桶牛奶，你可以获得一整天的营养需求与饱腹感，不要担心喝不完，只需要拿起来在嘴边晃动两下就可以发出喝水的声音，那之后，整桶牛奶就会被你收入腹中（不包括桶）。<br> 铁桶头盔<br> 若你在铁桶于空桶状态下将它戴在头上，你总有一种自己会变得步履蹒跚的错觉，当然，与之相对的是铁桶带给你的安全感，铁桶会为你提供3点临时生命，并且会随着临时生命消耗程度出现被撞击、变得干瘪、直接从头顶落下的样子，切换场景后铁桶将恢复原样。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',4)])])}const m=a(d,[["render",l]]);export{f as __pageData,m as default};
